import{_ as i,o as t,c as n,a}from"./chunks/framework.BHSVNLI7.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"en/tutorials/foundations/kernel-mini-config.md","filePath":"en/tutorials/foundations/kernel-mini-config.md","lastUpdated":null}'),s={name:"en/tutorials/foundations/kernel-mini-config.md"};function o(r,e,l,d,c,h){return t(),n("div",null,[...e[0]||(e[0]=[a(`<h2 id="what-we-re-doing" tabindex="-1">What We&#39;re Doing <a class="header-anchor" href="#what-we-re-doing" aria-label="Permalink to &quot;What We&#39;re Doing&quot;">​</a></h2><p>In this section, we&#39;re going to do something many people won&#39;t tell you about — designing a streamlined kernel configuration from scratch, instead of blindly using <code>defconfig</code>. We&#39;ll end up with a kernel config containing only the minimal feature set required to boot the QEMU virt machine. It has just 442 <code>=y</code> config options, whereas <code>defconfig</code> has 952.</p><p>Wait, we&#39;re getting our hands dirty this soon? Yep, why not? Haha! Building a kernel config ourselves from the ground up — isn&#39;t that awesome?</p><h2 id="what-to-know" tabindex="-1">What to Know <a class="header-anchor" href="#what-to-know" aria-label="Permalink to &quot;What to Know&quot;">​</a></h2><h3 id="the-problem-with-defconfig" tabindex="-1">The Problem with defconfig <a class="header-anchor" href="#the-problem-with-defconfig" aria-label="Permalink to &quot;The Problem with defconfig&quot;">​</a></h3><p><code>defconfig</code> is a predefined default configuration in the kernel source tree. For ARM64, it&#39;s located at <code>arch/arm64/configs/defconfig</code>. Running <code>make defconfig</code> gives you a &quot;working&quot; kernel config, which sounds great. The problem is that this config includes drivers for a massive number of real SoCs — GPUs, audio, and various board peripheral drivers. For kernel learning with the QEMU virt machine, we don&#39;t need any of this hardware support. It does nothing but slow down compilation and distract us.</p><p>To put it bluntly, more than half of the 952 <code>=y</code> options are things we&#39;ll never use. The hundreds of extra drivers compiled in are all dead code inside QEMU. Rather than learning inside a bloated kernel, we&#39;re better off trimming it down ourselves.</p><h3 id="the-three-step-configuration-process" tabindex="-1">The Three-Step Configuration Process <a class="header-anchor" href="#the-three-step-configuration-process" aria-label="Permalink to &quot;The Three-Step Configuration Process&quot;">​</a></h3><p>Our strategy is &quot;start from zero, enable on demand,&quot; broken down into three steps.</p><p>First, we use <code>allnoconfig</code> to generate a baseline config with almost everything disabled. This target sets all non-essential options to <code>n</code>, keeping only the hard dependencies of the architecture itself. For ARM64, the generated <code>.config</code> has only a few dozen options enabled, with everything else turned off.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> third_party/linux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=aarch64-linux-gnu-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     O=../../out/build_latest_arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> allnoconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Second, we use <code>merge_config.sh</code> to merge in our prepared config fragment. This script lives in the <code>scripts/kconfig/</code> directory of the kernel source. It works by merging options from the fragment file into the baseline config one by one — encountering <code>=y</code> enables them, and encountering <code>=m</code> sets them as modules. The <code>-m</code> parameter is followed by the path to the target <code>.config</code> file:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/kconfig/merge_config.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    ../../out/build_latest_arm64/.config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    ../../configs/arm64-qemu-virt-learn.config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Third, we use <code>olddefconfig</code> to have the kernel build system automatically fill in all dependencies. Our hand-written fragment only lists the options &quot;we know we need,&quot; but kernel configs have tons of implicit dependencies — for example, enabling <code>CONFIG_PRINTK=y</code> might require several other config options. <code>olddefconfig</code> traverses the entire config tree, automatically filling in all missing dependencies and applying default values to any newly introduced options:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=aarch64-linux-gnu-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     O=../../out/build_latest_arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> olddefconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>After these three steps, the final <code>.config</code> inflates from a few dozen options to 442 — the extras are all dependencies automatically filled in by <code>olddefconfig</code>. This number is still less than half of <code>defconfig</code>, and every enabled option can be traced back to a specific requirement in our fragment.</p><h3 id="design-philosophy-of-the-config-fragment" tabindex="-1">Design Philosophy of the Config Fragment <a class="header-anchor" href="#design-philosophy-of-the-config-fragment" aria-label="Permalink to &quot;Design Philosophy of the Config Fragment&quot;">​</a></h3><p>Our prepared fragment file is <a href="./configs/arm64-qemu-virt-learn.config">configs/arm64-qemu-virt-learn.config</a>. It&#39;s organized by functional category, with each group annotated with comments explaining &quot;why we need these options.&quot; Of course, you might wonder what all these things are. If you&#39;re not entirely sure — a great approach is to use a recursive descent method to look up the related concepts. Let&#39;s quickly run through what these are:</p><p>First, the platform basics. The ARM64 architecture itself is mandatory, and SMP (Symmetric Multiprocessing) must be enabled since our QEMU launch will configure two CPU cores:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CONFIG_ARM64=y</span></span>
<span class="line"><span>CONFIG_64BIT=y</span></span>
<span class="line"><span>CONFIG_SMP=y</span></span>
<span class="line"><span>CONFIG_NR_CPUS=2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Next is the serial console. The QEMU virt machine uses the ARM PL011 UART for serial output, which is exactly what the <code>console=ttyAMA0</code> kernel boot parameter points to. Without these options, you&#39;ll see nothing after the kernel boots — no boot logs, no shell prompt, just dead silence:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CONFIG_TTY=y</span></span>
<span class="line"><span>CONFIG_SERIAL_AMBA_PL011=y</span></span>
<span class="line"><span>CONFIG_SERIAL_AMBA_PL011_CONSOLE=y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Then comes initramfs support. Our rootfs will be packaged as a cpio.gz file loaded as an initrd, so the kernel must support gzip decompression to unpack it:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CONFIG_BLK_DEV_INITRD=y</span></span>
<span class="line"><span>CONFIG_RD_GZIP=y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>On the filesystem front, <code>devtmpfs</code> tells the kernel to automatically create device nodes under <code>/dev</code>, while <code>procfs</code> and <code>sysfs</code> provide kernel information interfaces for <code>/proc</code> and <code>/sys</code> respectively, and <code>tmpfs</code> is for memory-based filesystems. These four are the basic prerequisites for BusyBox shell to work properly. The kernel module related configs let us load and unload <code>.ko</code> modules later on, and the debugging support group (<code>DEBUG_INFO</code>, <code>GDB_SCRIPTS</code>, <code>KALLSYMS</code>) is prepared for GDB remote debugging.</p><p>The entire fragment is about 40 lines, with each config option accompanied by a comment explaining its purpose and dependencies. This &quot;minimal + annotated&quot; approach turns the config file itself into a study note.</p><h3 id="pitfalls-we-hit" tabindex="-1">Pitfalls We Hit <a class="header-anchor" href="#pitfalls-we-hit" aria-label="Permalink to &quot;Pitfalls We Hit&quot;">​</a></h3><p>This three-step process sounds simple, but we ran into quite a few pitfalls along the way. Here are the most noteworthy ones.</p><p><strong>&quot;The source tree is not clean&quot;</strong></p><p>This is the most common issue. The kernel Makefile has a check (in the <code>outputmakefile</code> target of <code>Makefile</code>) that, when using <code>O=</code> for out-of-tree builds, detects whether a <code>.config</code> file, a <code>include/config/</code> directory, or a <code>arch/arm64/include/generated/</code> directory exists in the source tree root. If it detects any of them, it deems the &quot;source tree not clean&quot; and refuses to continue.</p><p>Here&#39;s what happened to us: we had previously run a defconfig test directly in the source tree. Although we later cleaned up most artifacts with <code>make mrproper</code>, running <code>merge_config.sh</code> creates a <code>.config</code> file in the source tree root as a side effect, which caused subsequent <code>olddefconfig</code> runs to fail. The fix is straightforward — manually delete the leftover <code>.config</code>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> third_party/linux/.config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The core principle to prevent this issue: when building with <code>O=</code>, never run make directly inside the source tree. If you absolutely must operate inside the source tree (e.g., <code>merge_config.sh</code>), immediately check and clean up <code>.config</code> afterward.</p><p><strong>merge_config.sh Parameters</strong></p><p>The <code>-m</code> parameter must be followed by the full path to the target <code>.config</code> file, not a directory path. It modifies this file in place, merging the fragment options into it. So the correct invocation is <code>merge_config.sh -m &lt;output_dir&gt;/.config &lt;fragment&gt;</code>, not <code>merge_config.sh -m &lt;output_dir&gt; &lt;fragment&gt;</code>.</p><p><strong>Forgetting to Set ARCH and Building for x86</strong></p><p>This is a classic pitfall. The kernel build system determines the target architecture based on the <code>ARCH</code> variable; if unset, it defaults to the host architecture (x86_64 in WSL2). If <code>CROSS_COMPILE</code> is unset, it uses the native gcc. The result is that <code>make -j14</code> completes and outputs <code>arch/x86/boot/bzImage is ready</code> — a whole lot of compiling for nothing.</p><p>There are two solutions: either append <code>ARCH=arm64 CROSS_COMPILE=aarch64-linux-gnu-</code> to every make command, or export these two variables in the shell. The latter is less tedious, but keep in mind that export only affects the current shell session — close the terminal and you&#39;ll need to set them again.</p><p><strong>Working Directory and make -C</strong></p><p>Running <code>make O=... Image</code> directly from the project root <code>PenguinLab/</code> will throw a <code>No targets specified and no makefile found</code> error because the project root doesn&#39;t contain the kernel&#39;s Makefile. You either need to <code>cd third_party/linux</code> first before running make, or use <code>make -C third_party/linux</code> to explicitly specify the source directory.</p><h2 id="try-it-yourself" tabindex="-1">Try It Yourself <a class="header-anchor" href="#try-it-yourself" aria-label="Permalink to &quot;Try It Yourself&quot;">​</a></h2><ol><li>Confirm that <code>third_party/linux/Makefile</code> exists; if not, run <code>./scripts/linux-submodule.sh init</code> to fetch the kernel source</li><li>Execute the three-step configuration process in order: <code>allnoconfig</code> → <code>merge_config.sh</code> → <code>olddefconfig</code>, making sure to include <code>ARCH</code> and <code>CROSS_COMPILE</code> with each step</li><li>Use <code>grep -c &quot;=y&quot; out/build_latest_arm64/.config</code> to count the final number of config options — you should see a number between 400 and 500</li><li>Use <code>diff &lt;(grep &quot;=y&quot; out/build_latest_arm64/.config | sort) &lt;(grep &quot;=y&quot; &lt;(make ARCH=arm64 O=../../out/build_latest_arm64 defconfig &amp;&amp; cat ../../out/build_latest_arm64/.config) | sort)</code> to compare it against defconfig and see what we cut out</li></ol><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><ul><li><a href="https://www.kernel.org/doc/html/latest/kbuild/kbuild.html" target="_blank" rel="noreferrer">Kbuild Kernel Build System Documentation</a> — Official definitions for variables like <code>ARCH</code>, <code>CROSS_COMPILE</code>, and <code>O=</code></li><li><a href="https://docs.kernel.org/admin-guide/README.html" target="_blank" rel="noreferrer">Linux Kernel Build Instructions</a> — The official kernel.org getting-started guide for building the kernel</li><li><a href="./configs/arm64-qemu-virt-learn.config">configs/arm64-qemu-virt-learn.config</a> — Our mini config fragment file, with comments on every config option</li></ul>`,44)])])}const g=i(s,[["render",o]]);export{u as __pageData,g as default};
